import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getEventById, getEventDetailWithTickets, getPublicTicketTypesByEvent } from "../services/eventService";
import { Button, Card, Badge, Container, Row, Col } from "react-bootstrap";
import { getUserFromLocalStorage } from "../services/authService";

function EventDetailPage() {
  const [event, setEvent] = useState(null);
  const [tickets, setTickets] = useState([]);
  const [loading, setLoading] = useState(true);
  const { id } = useParams(); // Get event ID from the URL
  const navigate = useNavigate();
  const user = getUserFromLocalStorage();
  const isAdmin = user?.role === "admin";

  useEffect(() => {
    const fetchEventDetails = async () => {
      try {
        setLoading(true);
        const response = await getEventDetailWithTickets(id, isAdmin);
        setEvent(response.data?.data || {});
        setTickets(response.data?.data?.ticket_types || []);
      } catch (error) {
        console.error("Lỗi khi tải chi tiết sự kiện:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchEventDetails();
  }, [id, isAdmin]);

  const handlePurchase = (ticketTypeId) => {
    console.log("Mua vé với loại vé ID:", ticketTypeId);
    // Gọi API thanh toán để xử lý
  };

  if (loading) {
    return <div>Đang tải chi tiết sự kiện...</div>;
  }

  if (!event) {
    return <div>Sự kiện không tồn tại.</div>;
  }

  return (
    <Container className="my-5">
      <Row>
        <Col md={8}>
          <Card>
            <Card.Img
              variant="top"
              src={event.banner_image || "https://via.placeholder.com/600x400?text=No+Image"}
              alt={event.title}
            />
            <Card.Body>
              <Card.Title>{event.title}</Card.Title>
              <Card.Text>{event.description}</Card.Text>
              <Badge pill bg="primary">
                {event.location}
              </Badge>
              <div className="mt-3">
                {tickets.length > 0 ? (
                  tickets.map((ticket) => (
                    <div key={ticket.id} className="mb-3">
                      <h5>{ticket.type_name}</h5>
                      <p>{ticket.description}</p>
                      <Button variant="success" onClick={() => handlePurchase(ticket.id)}>
                        Mua vé ({ticket.price} VND)
                      </Button>
                    </div>
                  ))
                ) : (
                  <p>Không có vé bán cho sự kiện này.</p>
                )}
              </div>
            </Card.Body>
          </Card>
        </Col>
        <Col md={4}>
          <Card>
            <Card.Body>
              <Card.Title>Thông tin vé</Card.Title>
              <Card.Text>
                Loại vé: <strong>{event.ticket_type}</strong>
              </Card.Text>
              <Card.Text>
                Số lượng: <strong>{event.ticket_count}</strong>
              </Card.Text>
              <Card.Text>
                Giá: <strong>{event.ticket_price} VND</strong>
              </Card.Text>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
